class Solution:
    def magnificentSets(self, n, edges):
        parent = list(range(n + 1))
        rank_ = [0] * (n + 1)
        parity = [0] * (n + 1)

        def find(x):
            root, p = x, 0
            while parent[root] != root:
                p ^= parity[root]
                root = parent[root]
            # path compression with parity fix-up
            cur, cp = x, 0
            while parent[cur] != root:
                nxt = parent[cur]
                next_p = cp ^ parity[cur]
                parent[cur] = root
                parity[cur] = p ^ cp
                cur, cp = nxt, next_p
            return root, p

        ok = True
        for a, b in edges:
            ra, pa = find(a)
            rb, pb = find(b)
            if ra == rb:
                if pa == pb:
                    ok = False
            else:
                if rank_[ra] < rank_[rb]:
                    ra, rb = rb, ra
                    pa, pb = pb, pa
                parent[rb] = ra
                parity[rb] = pa ^ pb ^ 1
                if rank_[ra] == rank_[rb]:
                    rank_[ra] += 1
        if not ok:
            return -1

        adj = [[] for _ in range(n + 1)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)

        comp_of = [0] * (n + 1)
        comps = 0
        for i in range(1, n + 1):
            if comp_of[i] == 0:
                comps += 1
                comp_of[i] = comps
                stack = [i]
                while stack:
                    u = stack.pop()
                    for v in adj[u]:
                        if comp_of[v] == 0:
                            comp_of[v] = comps
                            stack.append(v)

        best = [0] * (comps + 1)
        from collections import deque
        for start in range(1, n + 1):
            dist = {start: 0}
            q = deque([start])
            far = 0
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if v not in dist:
                        dist[v] = dist[u] + 1
                        far = max(far, dist[v])
                        q.append(v)
            groups = far + 1
            c = comp_of[start]
            if groups > best[c]:
                best[c] = groups
        return sum(best[1:comps + 1])

