class Solution:
    def magnificentSets(self, n, edges):
        from collections import deque, defaultdict
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)

        visited = [False] * (n + 1)
        comps = []
        for i in range(1, n + 1):
            if not visited[i]:
                comp = []
                stack = [i]
                visited[i] = True
                while stack:
                    u = stack.pop()
                    comp.append(u)
                    for v in adj[u]:
                        if not visited[v]:
                            visited[v] = True
                            stack.append(v)
                comps.append(comp)

        color = [-1] * (n + 1)
        for comp in comps:
            start = comp[0]
            color[start] = 0
            q = deque([start])
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if color[v] == -1:
                        color[v] = color[u] ^ 1
                        q.append(v)
                    elif color[v] == color[u]:
                        return -1

        total = 0
        for comp in comps:
            best = 0
            for start in comp:
                dist = {start: 0}
                q = deque([start])
                far = 0
                while q:
                    u = q.popleft()
                    for v in adj[u]:
                        if v not in dist:
                            dist[v] = dist[u] + 1
                            far = max(far, dist[v])
                            q.append(v)
                best = max(best, far + 1)
            total += best
        return total

