var magnificentSets = function(n, edges) {
    const adj = Array.from({ length: n + 1 }, () => []);
    for (const [a, b] of edges) {
        adj[a].push(b);
        adj[b].push(a);
    }

    const visited = new Array(n + 1).fill(false);
    const comps = [];
    for (let i = 1; i <= n; i++) {
        if (!visited[i]) {
            const comp = [];
            const stack = [i];
            visited[i] = true;
            while (stack.length) {
                const u = stack.pop();
                comp.push(u);
                for (const v of adj[u]) {
                    if (!visited[v]) {
                        visited[v] = true;
                        stack.push(v);
                    }
                }
            }
            comps.push(comp);
        }
    }

    const color = new Array(n + 1).fill(-1);
    for (const comp of comps) {
        const start = comp[0];
        color[start] = 0;
        const q = [start];
        let head = 0;
        while (head < q.length) {
            const u = q[head++];
            for (const v of adj[u]) {
                if (color[v] === -1) {
                    color[v] = color[u] ^ 1;
                    q.push(v);
                } else if (color[v] === color[u]) {
                    return -1;
                }
            }
        }
    }

    let total = 0;
    for (const comp of comps) {
        let best = 0;
        for (const start of comp) {
            const dist = new Map([[start, 0]]);
            const q = [start];
            let head = 0;
            let far = 0;
            while (head < q.length) {
                const u = q[head++];
                for (const v of adj[u]) {
                    if (!dist.has(v)) {
                        const d = dist.get(u) + 1;
                        dist.set(v, d);
                        if (d > far) far = d;
                        q.push(v);
                    }
                }
            }
            if (far + 1 > best) best = far + 1;
        }
        total += best;
    }
    return total;
};
